"use client";
import Image from "next/image";
import { useRouter } from "next/navigation";

// 1. กำหนด Interface ใหม่ (ตัด ctaText ออก)
interface BannerProps {
    title: string;
    subtitle: string;
    imgSrc: string;
}

export default function Banner({ title, subtitle, imgSrc }: BannerProps) {
    const router = useRouter();

    return (
        <div className="relative w-full h-[70vh] min-h-[500px] flex items-center overflow-hidden">
            {/* Background Image */}
            <div className="absolute inset-0 z-0">
                <Image 
                    src={imgSrc} 
                    alt="Banner Background"
                    fill
                    priority
                    className="object-cover"
                />
                <div className="absolute inset-0 bg-black/40 bg-gradient-to-r from-black/70 to-transparent"></div>
            </div>

            {/* Content Area */}
            <div className="relative z-10 max-w-7xl mx-auto px-10 w-full">
                <div className="max-w-2xl space-y-6 text-white">
                    <h1 className="text-5xl md:text-7xl font-serif leading-tight drop-shadow-lg">
                        {title}
                    </h1>
                    
                    <p className="text-stone-200 text-lg md:text-xl max-w-lg leading-relaxed font-light">
                        {subtitle}
                    </p>

                    {/* ข้อความในปุ่มกำหนดตายตัวที่นี่ */}
                    <button 
                        onClick={() => router.push('/booking')}
                        className="bg-amber-600 hover:bg-amber-700 text-white px-12 py-4 rounded-full font-bold transition-all duration-300 transform hover:scale-105 shadow-2xl mt-4"
                    >
                        Book Now
                    </button>
                </div>
            </div>
        </div>
    );
}